## Unit Test Scenarios

```rust
#[cfg(test)]
mod tests {
    use super::*;

    // =========================================================================
    // Recovery Trigger Tests
    // =========================================================================

    #[test]
    fn test_trigger_region_id_extraction() {
        let trigger = RecoveryTrigger::QuorumLost {
            region_id: RegionId::new_for_test(1, 0),
            available_replicas: vec!["r1".to_string()],
            required_quorum: 2,
        };

        assert_eq!(trigger.region_id(), RegionId::new_for_test(1, 0));
    }

    #[test]
    fn test_trigger_critical_classification() {
        let critical = RecoveryTrigger::QuorumLost {
            region_id: RegionId::new_for_test(1, 0),
            available_replicas: vec![],
            required_quorum: 2,
        };
        assert!(critical.is_critical());

        let non_critical = RecoveryTrigger::ManualTrigger {
            region_id: RegionId::new_for_test(1, 0),
            initiator: "admin".to_string(),
            reason: None,
        };
        assert!(!non_critical.is_critical());
    }

    // =========================================================================
    // Symbol Collection Tests
    // =========================================================================

    #[test]
    fn test_collector_deduplicates_by_esi() {
        let mut collector = RecoveryCollector::new(RecoveryConfig::default());

        // Add same ESI from different replicas
        let symbol1 = Symbol::new_for_test(1, 0, 5, &[1, 2, 3]);
        let symbol2 = Symbol::new_for_test(1, 0, 5, &[1, 2, 3]); // Same ESI

        collector.add_collected(CollectedSymbol {
            symbol: symbol1,
            source_replica: "r1".to_string(),
            collected_at: Time::from_secs(0),
            verified: false,
        });

        collector.add_collected(CollectedSymbol {
            symbol: symbol2,
            source_replica: "r2".to_string(),
            collected_at: Time::from_secs(1),
            verified: false,
        });

        // Should only have one symbol
        assert_eq!(collector.symbols().len(), 1);
        assert_eq!(collector.metrics.symbols_duplicate, 1);
    }

    #[test]
    fn test_collector_progress_tracking() {
        let config = RecoveryConfig::default();
        let mut collector = RecoveryCollector::new(config);

        let progress = collector.progress();
        assert_eq!(progress.phase, RecoveryPhase::Initializing);
        assert_eq!(progress.symbols_collected, 0);
    }

    #[test]
    fn test_collector_can_decode_threshold() {
        let mut collector = RecoveryCollector::new(RecoveryConfig::default());
        collector.object_params = Some(ObjectParams::new(
            ObjectId::new_for_test(1),
            1000, 128, 1, 10, // K=10
        ));

        // Add 9 symbols (not enough)
        for i in 0..9 {
            collector.add_collected(create_test_collected_symbol(i));
        }
        assert!(!collector.can_decode());

        // Add 10th symbol (enough)
        collector.add_collected(create_test_collected_symbol(9));
        assert!(collector.can_decode());
    }

    #[test]
    fn test_collector_handles_corrupt_symbols() {
        let mut collector = RecoveryCollector::new(RecoveryConfig::default());

        // Attempt to add corrupt symbol
        let corrupt = create_corrupt_symbol();
        let result = collector.add_collected_with_verify(corrupt);

        assert!(result.is_err());
        assert_eq!(collector.metrics.symbols_corrupt, 1);
    }

    // =========================================================================
    // Decoding Tests
    // =========================================================================

    #[test]
    fn test_decoder_accumulates_symbols() {
        let mut decoder = StateDecoder::new(DecodingConfig::default());

        let symbol = Symbol::new_for_test(1, 0, 0, &[1, 2, 3]);
        decoder.add_symbol(&symbol).unwrap();

        assert_eq!(decoder.symbols_received(), 1);
    }

    #[test]
    fn test_decoder_rejects_insufficient_symbols() {
        let mut decoder = StateDecoder::new(DecodingConfig::default());
        let params = ObjectParams::new_for_test(1, 1000);

        // Add fewer than K symbols
        for i in 0..5 {
            let symbol = Symbol::new_for_test(1, 0, i, &[0u8; 128]);
            decoder.add_symbol(&symbol).unwrap();
        }

        let result = decoder.decode(&params);
        assert!(result.is_err());
